-- =============================================
-- TORVIAN TRANSFER — Region SEO Descriptions (Visible on Page)
-- Unique content per region × 5 languages (TR/EN/DE/PL/RU)
-- These populate the "About Region" section on each region page
-- =============================================

-- ============================================
-- 1. BELEK
-- ============================================
UPDATE regions SET
  description_tr = 'Belek, Antalya''nın en prestijli tatil bölgelerinden biridir. Dünyaca ünlü golf sahaları, 5 yıldızlı otelleri ve turkuaz sahilleriyle bilinen Belek, Antalya Havalimanı''na sadece 35 km mesafededir. Aile tatilcileri ve golf tutkunları için ideal olan bu bölgeye TORVIAN VIP transfer ile yaklaşık 30 dakikada konforlu bir şekilde ulaşabilirsiniz. Boğazkent ve Kadriye gibi komşu bölgelere de kolay erişim sağlar.',
  description_en = 'Belek is one of Antalya''s most prestigious resort destinations. Famous for its world-class golf courses, luxury 5-star hotels, and turquoise beaches, Belek sits just 35 km from Antalya Airport. With TORVIAN VIP transfer, you can reach Belek in approximately 30 minutes in comfort. Ideal for family holidaymakers and golf enthusiasts, Belek also offers easy access to nearby areas like Boğazkent and Kadriye.',
  description_de = 'Belek ist eines der exklusivsten Urlaubsziele Antalyas. Bekannt für erstklassige Golfplätze, luxuriöse 5-Sterne-Hotels und türkisfarbene Strände, liegt Belek nur 35 km vom Flughafen Antalya entfernt. Mit dem TORVIAN VIP-Transfer erreichen Sie Belek in etwa 30 Minuten bequem. Ideal für Familien und Golfbegeisterte, bietet Belek auch einfachen Zugang zu Nachbarorten wie Boğazkent und Kadriye.',
  description_pl = 'Belek to jeden z najbardziej prestiżowych kurortów w Antalyi. Znany ze światowej klasy pól golfowych, luksusowych hoteli 5-gwiazdkowych i turkusowych plaż, Belek znajduje się zaledwie 35 km od lotniska Antalya. Transferem VIP TORVIAN dotrzesz do Belek w około 30 minut w komforcie. Idealny dla rodzin i miłośników golfa, Belek zapewnia również łatwy dostęp do pobliskich miejscowości, takich jak Boğazkent i Kadriye.',
  description_ru = 'Белек — один из самых престижных курортных регионов Анталии. Известный своими гольф-полями мирового класса, роскошными 5-звёздочными отелями и бирюзовыми пляжами, Белек расположен всего в 35 км от аэропорта Анталии. С VIP-трансфером TORVIAN вы доберётесь до Белека примерно за 30 минут. Идеально подходит для семей и любителей гольфа, а также обеспечивает лёгкий доступ к соседним районам — Богазкент и Кадрие.'
WHERE slug = 'belek';

-- ============================================
-- 2. SIDE
-- ============================================
UPDATE regions SET
  description_tr = 'Side, Antalya''nın en tarihi ve büyüleyici tatil beldelerinden biridir. Antik tiyatrosu, Apollon Tapınağı ve altın kumsallarıyla ünlü Side, Antalya Havalimanı''ndan yaklaşık 75 km uzaklıktadır. Hem tarih meraklıları hem de plaj tatilcileri için mükemmel bir destinasyon olan Side''ye TORVIAN VIP transfer ile yaklaşık 1 saat 10 dakikada ulaşabilirsiniz. Manavgat Şelalesi ve antik çarşı gibi popüler noktalar da yakınındadır.',
  description_en = 'Side is one of Antalya''s most historic and enchanting resort towns. Famous for its ancient theatre, the Temple of Apollo, and golden sandy beaches, Side lies approximately 75 km from Antalya Airport. A perfect destination for both history lovers and beach holidaymakers, you can reach Side in about 1 hour 10 minutes with TORVIAN VIP transfer. Popular attractions like the Manavgat Waterfall and ancient bazaar are nearby.',
  description_de = 'Side gehört zu den historischsten und bezauberndsten Urlaubsorten Antalyas. Berühmt für sein antikes Theater, den Apollontempel und goldgelbe Sandstrände, liegt Side etwa 75 km vom Flughafen Antalya entfernt. Ideal für Geschichtsliebhaber und Strandurlauber, erreichen Sie Side mit dem TORVIAN VIP-Transfer in ca. 1 Stunde 10 Minuten. Beliebte Sehenswürdigkeiten wie der Manavgat-Wasserfall sind in der Nähe.',
  description_pl = 'Side to jedno z najbardziej historycznych i urokliwych miejsc w Antalyi. Znane z antycznego teatru, Świątyni Apollina i złocistych plaż, Side leży około 75 km od lotniska Antalya. Idealne miejsce zarówno dla miłośników historii, jak i plażowiczów — transferem VIP TORVIAN dotrzesz do Side w około 1 godzinę 10 minut. Pobliskie atrakcje to m.in. Wodospad Manavgat i antyczny bazar.',
  description_ru = 'Сиде — один из самых исторических и очаровательных курортных городов Анталии. Знаменитый античным театром, Храмом Аполлона и золотыми песчаными пляжами, Сиде расположен примерно в 75 км от аэропорта Анталии. Идеальное место как для любителей истории, так и для пляжного отдыха — с VIP-трансфером TORVIAN вы доберётесь до Сиде примерно за 1 час 10 минут. Рядом — водопад Манавгат и античный базар.'
WHERE slug = 'side';

-- ============================================
-- 3. ALANYA
-- ============================================
UPDATE regions SET
  description_tr = 'Alanya, Antalya''nın doğusunda yer alan canlı ve renkli bir tatil cenneti. İkonik Alanya Kalesi, Kleopatra Plajı ve Damlataş Mağarası ile tanınan bölge, Antalya Havalimanı''ndan yaklaşık 130 km uzaklıktadır. TORVIAN VIP transfer ile konforlu bir araçla yaklaşık 2 saatte ulaşabilirsiniz. Uzun mesafeye rağmen profesyonel sürücülerimiz ve lüks araçlarımızla yolculuk oldukça rahat geçer. Alanya''nın gece hayatı, alışveriş olanakları ve su sporları her yaş grubuna hitap eder.',
  description_en = 'Alanya is a vibrant holiday destination located on the eastern coast of Antalya. Known for its iconic Alanya Castle, Cleopatra Beach, and Damlataş Cave, the region sits approximately 130 km from Antalya Airport. With TORVIAN VIP transfer, you''ll reach Alanya in about 2 hours in a comfortable, luxury vehicle. Despite the longer journey, our professional drivers ensure a relaxing ride. Alanya offers fantastic nightlife, shopping, and water sports for all ages.',
  description_de = 'Alanya ist ein lebhaftes Urlaubsziel an der Ostküste Antalyas. Bekannt für die ikonische Burg von Alanya, den Kleopatra-Strand und die Damlataş-Höhle, liegt die Region etwa 130 km vom Flughafen Antalya entfernt. Mit dem TORVIAN VIP-Transfer erreichen Sie Alanya in etwa 2 Stunden in einem luxuriösen Fahrzeug. Trotz der längeren Strecke sorgen unsere professionellen Fahrer für eine entspannte Fahrt. Alanya bietet Nachtleben, Shopping und Wassersport für alle.',
  description_pl = 'Alanya to tętniący życiem kurort na wschodnim wybrzeżu Antalyi. Znana z ikonicznego zamku Alanya, Plaży Kleopatry i Jaskini Damlataş, miejscowość leży około 130 km od lotniska Antalya. Transferem VIP TORVIAN dotrzesz do Alanyi w około 2 godziny w komfortowym, luksusowym pojeździe. Mimo dłuższej trasy, nasi profesjonalni kierowcy zapewnią relaksującą podróż. Alanya oferuje życie nocne, zakupy i sporty wodne dla każdego.',
  description_ru = 'Аланья — яркий курортный город на восточном побережье Анталии. Известна своей крепостью, пляжем Клеопатры и пещерой Дамлаташ. Аланья расположена примерно в 130 км от аэропорта Анталии. С VIP-трансфером TORVIAN вы доберётесь туда за 2 часа в комфортном автомобиле. Несмотря на длинный путь, наши профессиональные водители обеспечат расслабляющую поездку. Аланья предлагает ночную жизнь, шопинг и водные развлечения.'
WHERE slug = 'alanya';

-- ============================================
-- 4. KEMER
-- ============================================
UPDATE regions SET
  description_tr = 'Kemer, Antalya''nın batısında Toros Dağları ile Akdeniz arasında sıkışmış doğa harikası bir tatil beldesidir. Turkuaz koyları, çam ormanları ve butik otelleriyle ünlü Kemer, havalimanına yaklaşık 45 km mesafededir. TORVIAN VIP transfer ile 40 dakikada bu cennet köşeye ulaşabilirsiniz. Faselis antik kenti, Yörük Parkı ve Tahtalı Dağı teleferik deneyimi Kemer''in başlıca turistik noktalarındandır.',
  description_en = 'Kemer is a stunning coastal resort nestled between the Taurus Mountains and the Mediterranean Sea on Antalya''s western coast. Known for its turquoise coves, pine forests, and boutique hotels, Kemer is about 45 km from the airport. With TORVIAN VIP transfer, you''ll arrive in just 40 minutes. Top attractions include the ancient city of Phaselis, Yörük Park, and the Tahtalı Mountain cable car experience.',
  description_de = 'Kemer ist ein atemberaubender Küstenort zwischen dem Taurusgebirge und dem Mittelmeer an der Westküste Antalyas. Bekannt für türkisfarbene Buchten, Kiefernwälder und Boutique-Hotels, liegt Kemer etwa 45 km vom Flughafen entfernt. Mit dem TORVIAN VIP-Transfer sind Sie in nur 40 Minuten da. Top-Attraktionen: die antike Stadt Phaselis, der Yörük-Park und die Seilbahn zum Berg Tahtalı.',
  description_pl = 'Kemer to urokliwy nadmorski kurort położony między górami Taurus a Morzem Śródziemnym na zachodnim wybrzeżu Antalyi. Znany z turkusowych zatok, sosnowych lasów i butikowych hoteli, Kemer leży około 45 km od lotniska. Transferem VIP TORVIAN dotrzesz tam w zaledwie 40 minut. Czołowe atrakcje: antyczne miasto Phaselis, Park Yörük i kolejka linowa na górę Tahtalı.',
  description_ru = 'Кемер — живописный курортный посёлок между горами Таурус и Средиземным морем на западном побережье Анталии. Известен бирюзовыми бухтами, сосновыми лесами и бутик-отелями. Расположен в 45 км от аэропорта. С VIP-трансфером TORVIAN вы доберётесь за 40 минут. Главные достопримечательности: античный город Фаселис, парк Йорюк и канатная дорога на гору Тахталы.'
WHERE slug = 'kemer';

-- ============================================
-- 5. LARA
-- ============================================
UPDATE regions SET
  description_tr = 'Lara, Antalya şehir merkezinin hemen doğusunda yer alan prestijli bir sahil bölgesidir. Dev all-inclusive otelleri, uzun kumsalı ve aktif gece hayatıyla tanınır. Havalimanına sadece 12 km mesafede olan Lara, TORVIAN VIP transfer ile 15 dakikada ulaşılabilir. Düden Şelalesi ve Lara Plajı başlıca gezilecek yerlerdendir. Konyaaltı ve şehir merkezine de kolay ulaşım sağlar.',
  description_en = 'Lara is a prestigious coastal district located just east of Antalya city center. Known for its massive all-inclusive resorts, long sandy beach, and vibrant nightlife, Lara sits only 12 km from the airport. You''ll reach Lara in just 15 minutes with TORVIAN VIP transfer. Key attractions include the Düden Waterfalls and Lara Beach. It also provides easy access to Konyaaltı and the city center.',
  description_de = 'Lara ist ein prestigeträchtiges Küstenviertel direkt östlich des Stadtzentrums von Antalya. Bekannt für riesige All-Inclusive-Resorts, lange Sandstrände und lebhaftes Nachtleben, liegt Lara nur 12 km vom Flughafen entfernt. Mit dem TORVIAN VIP-Transfer erreichen Sie Lara in nur 15 Minuten. Hauptattraktionen: Düden-Wasserfälle und Lara Beach.',
  description_pl = 'Lara to prestiżowa dzielnica nadmorska położona tuż na wschód od centrum Antalyi. Znana z ogromnych hoteli all-inclusive, długiej piaszczystej plaży i tętniącego życiem nocnego. Lara jest oddalona zaledwie 12 km od lotniska — transferem VIP TORVIAN dotrzesz tam w 15 minut. Główne atrakcje: Wodospady Düden i Plaża Lara.',
  description_ru = 'Лара — престижный прибрежный район к востоку от центра Анталии. Известен огромными all-inclusive отелями, длинным песчаным пляжем и оживлённой ночной жизнью. Лара расположена всего в 12 км от аэропорта — с VIP-трансфером TORVIAN вы доберётесь за 15 минут. Главные достопримечательности: водопады Дюден и пляж Лара.'
WHERE slug = 'lara';

-- ============================================
-- 6. KUNDU
-- ============================================
UPDATE regions SET
  description_tr = 'Kundu, Antalya''nın en lüks otel bölgelerinden biridir. Lara''nın devamında yer alan bu bölge, tematik otelleriyle ve geniş sahil şeridiyle tanınır. Havalimanına sadece 15 km uzaklıktadır ve TORVIAN VIP transfer ile 18 dakikada ulaşabilirsiniz. Aileler için ideal olan Kundu, sakin ve güvenli bir tatil ortamı sunar.',
  description_en = 'Kundu is one of Antalya''s most luxurious hotel districts. An extension of the Lara area, Kundu is famous for its themed resort hotels and wide beachfront. Only 15 km from the airport, you can reach Kundu in 18 minutes with TORVIAN VIP transfer. Ideal for families, Kundu offers a calm and secure holiday environment.',
  description_de = 'Kundu ist einer der luxuriösesten Hotelgebiete Antalyas. Als Erweiterung des Lara-Gebiets ist Kundu für seine Themenresorts und die breite Strandpromenade bekannt. Nur 15 km vom Flughafen entfernt, erreichen Sie Kundu mit dem TORVIAN VIP-Transfer in 18 Minuten. Ideal für Familien bietet Kundu eine ruhige und sichere Urlaubsumgebung.',
  description_pl = 'Kundu to jeden z najbardziej luksusowych regionów hotelowych Antalyi. Będąc przedłużeniem strefy Lara, Kundu słynie z tematycznych resortów i szerokiego pasa nadmorskiego. Zaledwie 15 km od lotniska — transferem VIP TORVIAN dotrzesz tam w 18 minut. Idealny dla rodzin, Kundu oferuje spokojne i bezpieczne środowisko wypoczynkowe.',
  description_ru = 'Кунду — один из самых роскошных отельных районов Анталии. Являясь продолжением Лары, Кунду знаменит тематическими резорт-отелями и широкой пляжной полосой. Всего 15 км от аэропорта — с VIP-трансфером TORVIAN вы доберётесь за 18 минут. Идеально для семей — Кунду предлагает спокойный и безопасный отдых.'
WHERE slug = 'kundu';

-- ============================================
-- 7. KAŞ
-- ============================================
UPDATE regions SET
  description_tr = 'Kaş, Antalya''nın güneybatısında bulunan şirin ve otantik bir Akdeniz kasabasıdır. Dar sokakları, renkli bugenvil çiçekleri, dalış noktaları ve Yunan adası Meis manzarasıyla ünlüdür. Havalimanından yaklaşık 190 km uzaklıkta olan Kaş''a TORVIAN VIP transfer ile konforlu bir yolculukla ulaşabilirsiniz. Butik oteller, deniz kayağı ve kano gibi aktiviteler Kaş''ı benzersiz kılar.',
  description_en = 'Kas is a charming and authentic Mediterranean town on Antalya''s southwestern coast. Famous for its narrow streets, colorful bougainvillea flowers, diving spots, and views of the Greek island of Meis (Kastellorizo), Kas sits about 190 km from the airport. Despite the distance, TORVIAN VIP transfer ensures a comfortable journey. Boutique hotels, sea kayaking, and diving make Kas a unique destination.',
  description_de = 'Kaş ist eine charmante und authentische Mittelmeerstadt an der Südwestküste Antalyas. Berühmt für enge Gassen, bunte Bougainvillea, Tauchplätze und den Blick auf die griechische Insel Meis, liegt Kaş etwa 190 km vom Flughafen entfernt. Trotz der Entfernung sorgt der TORVIAN VIP-Transfer für eine komfortable Anreise. Boutique-Hotels, Seekajak und Tauchen machen Kaş einzigartig.',
  description_pl = 'Kaş to urocze i autentyczne miasteczko śródziemnomorskie na południowo-zachodnim wybrzeżu Antalyi. Znane z wąskich uliczek, kolorowych bugenwilli, miejsc do nurkowania i widoku na grecką wyspę Meis. Kaş leży około 190 km od lotniska, ale dzięki VIP transferowi TORVIAN podróż jest komfortowa. Butikowe hotele, kajakarstwo morskie i nurkowanie czynią Kaş wyjątkowym.',
  description_ru = 'Каш — очаровательный аутентичный средиземноморский городок на юго-западном побережье Анталии. Знаменит узкими улочками, яркой бугенвиллией, дайвинг-спотами и видом на греческий остров Мейс. До Каша около 190 км от аэропорта, но VIP-трансфер TORVIAN обеспечит комфортную поездку. Бутик-отели, морской каякинг и дайвинг делают Каш уникальным.'
WHERE slug = 'kas';

-- ============================================
-- 8. MANAVGAT
-- ============================================
UPDATE regions SET
  description_tr = 'Manavgat, dünyaca ünlü şelalesi ve bereketli ovasıyla tanınan bir Antalya ilçesidir. Antalya Havalimanı''na yaklaşık 70 km mesafededir. Side antik kentine komşu olan Manavgat, nehir turu, rafting ve doğa yürüyüşü gibi aktiviteler sunar. TORVIAN VIP transfer ile yaklaşık 1 saat içinde ulaşabilirsiniz. Pazar günleri kurulan dev Manavgat Pazarı turistlerin favorisidir.',
  description_en = 'Manavgat is an Antalya district famous for its world-renowned waterfall and fertile plain. Located about 70 km from Antalya Airport, Manavgat neighbors the ancient city of Side and offers river tours, rafting, and nature hikes. You can reach Manavgat in about 1 hour with TORVIAN VIP transfer. The huge Manavgat Bazaar, held on market days, is a favorite among tourists.',
  description_de = 'Manavgat ist ein Bezirk in Antalya, berühmt für seinen weltbekannten Wasserfall und die fruchtbare Ebene. Etwa 70 km vom Flughafen entfernt, grenzt Manavgat an die antike Stadt Side und bietet Flusstouren, Rafting und Naturwanderungen. Mit dem TORVIAN VIP-Transfer erreichen Sie Manavgat in etwa 1 Stunde. Der riesige Manavgat-Basar ist bei Touristen sehr beliebt.',
  description_pl = 'Manavgat to dystrykt Antalyi znany ze słynnego wodospadu i żyznej równiny. Oddalony o około 70 km od lotniska, Manavgat sąsiaduje z antycznym miastem Side i oferuje rejsy rzeczne, rafting oraz piesze wędrówki. Transferem VIP TORVIAN dotrzesz tam w około 1 godzinę. Ogromny Bazar Manavgat jest ulubieńcem turystów.',
  description_ru = 'Манавгат — район Анталии, знаменитый всемирно известным водопадом и плодородной долиной. В 70 км от аэропорта, по соседству с античным городом Сиде. Манавгат предлагает речные круизы, рафтинг и пешие прогулки. С VIP-трансфером TORVIAN доберётесь за 1 час. Огромный базар Манавгат — любимое место туристов.'
WHERE slug = 'manavgat';

-- ============================================
-- 9. KONYAALTI
-- ============================================
UPDATE regions SET
  description_tr = 'Konyaaltı, Antalya şehir merkezinin batısında uzanan popüler bir sahil bölgesidir. Uzun çakıl plajı, modern sahil parkı ve Antalya Akvaryumu ile tanınır. Havalimanına sadece 15 km uzaklıktadır ve TORVIAN VIP transfer ile 20 dakikada ulaşılabilir. Şehir merkezine yürüme mesafesinde olan Konyaaltı, hem tatilciler hem de şehir gezginleri için idealdir.',
  description_en = 'Konyaaltı is a popular coastal district stretching along the western side of Antalya city center. Known for its long pebble beach, modern seaside park, and the Antalya Aquarium, it sits just 15 km from the airport. With TORVIAN VIP transfer, you''ll arrive in 20 minutes. Within walking distance of the city center, Konyaaltı is ideal for both beach holidays and city exploration.',
  description_de = 'Konyaaltı ist ein beliebtes Küstenviertel westlich des Stadtzentrums von Antalya. Bekannt für seinen langen Kiesstrand, den modernen Strandpark und das Antalya Aquarium, liegt es nur 15 km vom Flughafen entfernt. Mit dem TORVIAN VIP-Transfer sind Sie in 20 Minuten da. Konyaaltı liegt in Gehweite zum Stadtzentrum — ideal für Strand- und Städteurlaub.',
  description_pl = 'Konyaaltı to popularna dzielnica nadmorska rozciągająca się wzdłuż zachodniej strony centrum Antalyi. Znana z długiej kamienistej plaży, nowoczesnego parku nadmorskiego i Akwarium Antalya, leży zaledwie 15 km od lotniska. Transferem VIP TORVIAN dotrzesz tam w 20 minut. W odległości spaceru od centrum — idealne na plażę i zwiedzanie miasta.',
  description_ru = 'Коньяалты — популярный прибрежный район к западу от центра Анталии. Известен длинным галечным пляжем, современным парком и Аквариумом Анталии. Всего 15 км от аэропорта — с VIP-трансфером TORVIAN доберётесь за 20 минут. В пешей доступности от центра города — идеально для пляжного отдыха и городских прогулок.'
WHERE slug = 'konyaalti';

-- ============================================
-- 10. FETHIYE
-- ============================================
UPDATE regions SET
  description_tr = 'Fethiye, Muğla ili sınırında yer alan doğa harikası bir tatil beldesidir. Ölüdeniz, Kelebekler Vadisi ve Saklıkent Kanyonu gibi dünyaca ünlü doğal güzelliklere ev sahipliği yapar. Antalya Havalimanı''ndan yaklaşık 200 km mesafede olan Fethiye''ye TORVIAN VIP transfer ile konforlu bir yolculuk yapabilirsiniz. Yamaç paraşütü deneyimi için dünyanın en iyi noktalarından biridir.',
  description_en = 'Fethiye is a spectacular holiday town near the Muğla province border. Home to world-famous natural wonders like Ölüdeniz (Blue Lagoon), Butterfly Valley, and Saklıkent Canyon, it lies about 200 km from Antalya Airport. With TORVIAN VIP transfer, you can enjoy a comfortable journey. Fethiye is also one of the world''s best destinations for paragliding.',
  description_de = 'Fethiye ist eine spektakuläre Urlaubsstadt nahe der Grenze zur Provinz Muğla. Heimat weltberühmter Naturwunder wie Ölüdeniz (Blaue Lagune), Schmetterlingstal und Saklıkent-Schlucht. Etwa 200 km vom Flughafen entfernt, bietet der TORVIAN VIP-Transfer eine komfortable Anreise. Fethiye ist auch einer der besten Orte weltweit zum Paragliding.',
  description_pl = 'Fethiye to spektakularne miasteczko wakacyjne blisko granicy prowincji Muğla. Znane ze słynnych cudów natury: Ölüdeniz (Błękitna Laguna), Dolina Motyli i Kanion Saklıkent. Około 200 km od lotniska Antalya — transferem VIP TORVIAN podróż będzie komfortowa. Fethiye to także jedno z najlepszych miejsc na świecie do paralotniarstwa.',
  description_ru = 'Фетхие — потрясающий курортный город у границы провинции Мугла. Здесь находятся всемирно известные природные чудеса: Олюдениз (Голубая лагуна), Долина бабочек и каньон Саклыкент. Около 200 км от аэропорта — с VIP-трансфером TORVIAN путешествие будет комфортным. Фетхие — одно из лучших мест в мире для параглайдинга.'
WHERE slug = 'fethiye';

