-- ============================================
UPDATE regions SET
  description_tr = 'Marmaris, Ege ile Akdeniz''in buluştuğu muhteşem bir sahil kentidir. Canlı marina atmosferi, çam ormanları ve kristal berrak koylaryıla ünlüdür. Antalya Havalimanı''ndan yaklaşık 300 km mesafede olmasına rağmen TORVIAN VIP transfer ile konforlu lüks araçlarımızla ulaşabilirsiniz. Dalyan, İçmeler ve Turunç gibi yakın destinasyonlara da kolay erişim sağlar.',
  description_en = 'Marmaris is a spectacular coastal city where the Aegean meets the Mediterranean. Famous for its vibrant marina, pine-covered hills, and crystal-clear bays, it lies about 300 km from Antalya Airport. Despite the distance, TORVIAN VIP transfer provides a comfortable journey in luxury vehicles. Marmaris also offers easy access to nearby gems like Dalyan, İçmeler, and Turunç.',
  description_de = 'Marmaris ist eine spektakuläre Küstenstadt, wo die Ägäis auf das Mittelmeer trifft. Berühmt für den lebhaften Yachthafen, kieferbedeckte Hügel und kristallklare Buchten, liegt es etwa 300 km vom Flughafen entfernt. Der TORVIAN VIP-Transfer gewährleistet eine komfortable Reise. Nahegelegene Ziele wie Dalyan, İçmeler und Turunç sind leicht erreichbar.',
  description_pl = 'Marmaris to spektakularne nadmorskie miasto, gdzie Morze Egejskie spotyka się z Morzem Śródziemnym. Znane z tętniącej życiem mariny, zalesionych wzgórz i krystalicznie czystych zatok, leży około 300 km od lotniska Antalya. VIP transfer TORVIAN zapewni komfortową podróż luksusowym pojazdem. Łatwy dostęp do Dalyan, İçmeler i Turunç.',
  description_ru = 'Мармарис — великолепный прибрежный город, где Эгейское море встречается со Средиземным. Знаменит яхтенной мариной, сосновыми холмами и кристально чистыми бухтами. Около 300 км от аэропорта, но VIP-трансфер TORVIAN обеспечит комфортную поездку. Рядом — Дальян, Ичмелер и Турунч.'
WHERE slug = 'marmaris';

-- ============================================
-- 12. KADRIYE
-- ============================================
UPDATE regions SET
  description_tr = 'Kadriye, Belek''in hemen yanında yer alan sakin ve aile dostu bir tatil bölgesidir. Land of Legends tema parkına ev sahipliği yapan Kadriye, çocuklu aileler için mükemmel bir tercih. Havalimanına 30 km uzaklıktadır ve TORVIAN VIP transfer ile 25 dakikada ulaşılabilir. Golf sahaları ve plajlar da yakınındadır.',
  description_en = 'Kadriye is a peaceful, family-friendly resort area adjacent to Belek. Home to the Land of Legends theme park, Kadriye is a perfect choice for families with children. Located 30 km from the airport, you can reach Kadriye in just 25 minutes with TORVIAN VIP transfer. Golf courses and beaches are also nearby.',
  description_de = 'Kadriye ist ein ruhiges, familienfreundliches Urlaubsgebiet neben Belek. Hier befindet sich der Freizeitpark Land of Legends — perfekt für Familien. Nur 30 km vom Flughafen entfernt, erreichen Sie Kadriye mit dem TORVIAN VIP-Transfer in 25 Minuten. Golfplätze und Strände sind ebenfalls in der Nähe.',
  description_pl = 'Kadriye to spokojny, przyjazny rodzinom region wypoczynkowy obok Belek. To tutaj znajduje się park rozrywki Land of Legends — idealny wybór dla rodzin z dziećmi. 30 km od lotniska, transferem VIP TORVIAN dotrzesz w 25 minut. Pola golfowe i plaże w pobliżu.',
  description_ru = 'Кадрие — тихий семейный курортный район рядом с Белеком. Здесь находится тематический парк Land of Legends — отличный выбор для семей с детьми. В 30 км от аэропорта — с VIP-трансфером TORVIAN доберётесь за 25 минут. Гольф-поля и пляжи тоже рядом.'
WHERE slug = 'kadriye';

-- ============================================
-- 13. BOGAZKENT
-- ============================================
UPDATE regions SET
  description_tr = 'Boğazkent, Belek''in hemen güneyinde sakin ve doğal güzellikleriyle bilinen bir sahil beldesidir. Uzun kumsalı ve az kalabalık yapısıyla huzur arayan tatilciler için idealdir. Havalimanına 40 km mesafededir ve TORVIAN VIP transfer ile 35 dakikada ulaşılabilir.',
  description_en = 'Boğazkent is a tranquil coastal village just south of Belek, known for its natural beauty and unspoiled beaches. Perfect for travelers seeking peace and privacy, it sits 40 km from the airport. With TORVIAN VIP transfer, you''ll arrive in 35 minutes.',
  description_de = 'Boğazkent ist ein ruhiges Küstendorf südlich von Belek, bekannt für natürliche Schönheit und unberührte Strände. Ideal für Reisende, die Ruhe suchen. 40 km vom Flughafen, erreichbar in 35 Minuten mit TORVIAN VIP-Transfer.',
  description_pl = 'Boğazkent to spokojna nadmorska wioska na południe od Belek, znana z naturalnego piękna i dziewiczych plaż. Idealny dla podróżnych szukających spokoju. 40 km od lotniska, dojazd w 35 minut transferem VIP TORVIAN.',
  description_ru = 'Богазкент — тихая прибрежная деревня к югу от Белека, известная природной красотой и нетронутыми пляжами. Идеально для тех, кто ищет покой. 40 км от аэропорта — доберётесь за 35 минут с VIP-трансфером TORVIAN.'
WHERE slug = 'bogazkent';

-- ============================================
-- 14. EVRENSEKI
-- ============================================
UPDATE regions SET
  description_tr = 'Evrenseki, Side ile Manavgat arasında yer alan popüler bir tatil bölgesidir. Geniş kumsalları, aileler için uygun otelleri ve uygun fiyatlı tatil seçenekleriyle bilinir. Havalimanına yaklaşık 65 km mesafededir ve TORVIAN VIP transfer ile 1 saat içinde ulaşılabilir.',
  description_en = 'Evrenseki is a popular resort area located between Side and Manavgat. Known for its wide sandy beaches, family-friendly hotels, and affordable holiday options, it sits about 65 km from the airport. With TORVIAN VIP transfer, you''ll arrive within 1 hour.',
  description_de = 'Evrenseki ist ein beliebtes Urlaubsgebiet zwischen Side und Manavgat. Bekannt für breite Sandstrände, familienfreundliche Hotels und erschwingliche Urlaubsangebote. Etwa 65 km vom Flughafen, erreichbar in 1 Stunde mit TORVIAN VIP-Transfer.',
  description_pl = 'Evrenseki to popularny kurort położony między Side a Manavgat. Znany z szerokich piaszczystych plaż, hoteli przyjaznych rodzinom i przystępnych cen. Około 65 km od lotniska, dojazd w 1 godzinę transferem VIP TORVIAN.',
  description_ru = 'Эвренсеки — популярный курортный район между Сиде и Манавгатом. Известен широкими песчаными пляжами, семейными отелями и доступными ценами. Около 65 км от аэропорта — доберётесь за 1 час с VIP-трансфером TORVIAN.'
WHERE slug = 'evrenseki';

-- ============================================
-- 15. KIZILAGAC
-- ============================================
UPDATE regions SET
  description_tr = 'Kızılağaç, Side''nin doğusunda doğayla iç içe bir tatil noktasıdır. Sakin atmosferi, çam ormanları ve geniş sahilleriyle huzur arayanlar için biçilmiş kaftan. Havalimanına yaklaşık 80 km mesafededir ve TORVIAN VIP transfer ile 1 saat 15 dakikada ulaşılabilir.',
  description_en = 'Kızılağaç is a nature-embraced holiday spot east of Side. With its calm atmosphere, pine forests, and wide beaches, it''s tailor-made for travelers seeking tranquility. About 80 km from the airport, reachable in 1 hour 15 minutes with TORVIAN VIP transfer.',
  description_de = 'Kızılağaç ist ein naturnahes Urlaubsziel östlich von Side. Mit ruhiger Atmosphäre, Kiefernwäldern und breiten Stränden ideal für Erholungssuchende. Etwa 80 km vom Flughafen, in 1 Stunde 15 Minuten mit TORVIAN VIP-Transfer.',
  description_pl = 'Kızılağaç to otoczone naturą miejsce wypoczynkowe na wschód od Side. Spokojna atmosfera, sosnowe lasy i szerokie plaże — idealne dla szukających relaksu. Około 80 km od lotniska, dojazd w 1 godzinę 15 minut transferem VIP TORVIAN.',
  description_ru = 'Кызылагач — курортное место в окружении природы к востоку от Сиде. Тихая атмосфера, сосновые леса и широкие пляжи — идеально для желающих отдохнуть. Около 80 км от аэропорта — доберётесь за 1 час 15 минут с VIP-трансфером TORVIAN.'
WHERE slug = 'kizilagac';

-- ============================================
-- 16. BELDIBI
-- ============================================
UPDATE regions SET
  description_tr = 'Beldibi, Kemer''in kuzeyinde dağlar ve deniz arasında uzanan şirin bir tatil beldesidir. Doğa yürüyüşleri, mağara keşifleri ve sakin kumsallarıyla bilinir. Havalimanına yaklaşık 35 km mesafededir ve TORVIAN VIP transfer ile 30 dakikada ulaşılabilir.',
  description_en = 'Beldibi is a charming resort village stretching between mountains and sea, north of Kemer. Known for nature walks, cave exploration, and quiet beaches, it sits about 35 km from the airport. Reachable in 30 minutes with TORVIAN VIP transfer.',
  description_de = 'Beldibi ist ein charmantes Urlaubsdorf zwischen Bergen und Meer, nördlich von Kemer. Bekannt für Naturwanderungen, Höhlenentdeckungen und ruhige Strände. Etwa 35 km vom Flughafen, in 30 Minuten mit TORVIAN VIP-Transfer.',
  description_pl = 'Beldibi to urocza wioska turystyczna między górami a morzem, na północ od Kemer. Znana z wędrówek, eksploracji jaskiń i spokojnych plaż. Około 35 km od lotniska, dojazd w 30 minut transferem VIP TORVIAN.',
  description_ru = 'Бельдиби — очаровательный курортный посёлок между горами и морем, к северу от Кемера. Известен пешими прогулками, пещерами и тихими пляжами. 35 км от аэропорта — доберётесь за 30 минут с VIP-трансфером TORVIAN.'
WHERE slug = 'beldibi';

-- ============================================
-- 17. GOYNUK
-- ============================================
UPDATE regions SET
  description_tr = 'Göynük, muhteşem kanyonuyla dünyaca ünlü bir Kemer ilçesidir. Göynük Kanyonu''nda yüzme, rafting ve zipline yapabilirsiniz. Doğasever tatilciler için mükemmel olan bu bölge, havalimanına yaklaşık 40 km mesafededir. TORVIAN VIP transfer ile 35 dakikada ulaşılabilir.',
  description_en = 'Göynük is a Kemer sub-district world-famous for its spectacular canyon. At Göynük Canyon you can swim, raft, and zipline. Perfect for nature lovers, the area is about 40 km from the airport. Reachable in 35 minutes with TORVIAN VIP transfer.',
  description_de = 'Göynük ist ein Teilbezirk von Kemer, weltberühmt für seinen spektakulären Canyon. Im Göynük Canyon kann man schwimmen, raften und Seilrutschen. Ideal für Naturliebhaber: nur 40 km vom Flughafen, in 35 Minuten mit TORVIAN VIP-Transfer.',
  description_pl = 'Göynük to dzielnica Kemer słynąca ze spektakularnego kanionu. W Kanionie Göynük można pływać, spływać kajakiem i zjechać na tyrolce. Idealny dla miłośników natury — 40 km od lotniska, dojazd w 35 minut transferem VIP TORVIAN.',
  description_ru = 'Гёйнюк — район Кемера, всемирно известный своим каньоном. В каньоне Гёйнюк можно плавать, сплавляться и кататься на зиплайне. Идеально для любителей природы — 40 км от аэропорта, доберётесь за 35 минут с VIP-трансфером TORVIAN.'
WHERE slug = 'goynuk';

-- ============================================
-- 18. TEKIROVA
-- ============================================
UPDATE regions SET
  description_tr = 'Tekirova, Kemer''in güneyinde sakin ve doğayla iç içe küçük bir tatil beldesidir. Olimpos Teleferik (Tahtalı Dağı) ve Faselis antik kentine yakınlığıyla bilinir. Havalimanına yaklaşık 60 km mesafededir ve TORVIAN VIP transfer ile 50 dakikada ulaşılabilir.',
  description_en = 'Tekirova is a small, peaceful resort town south of Kemer, immersed in nature. Known for its proximity to the Olympos cable car (Mount Tahtalı) and the ancient city of Phaselis, it sits about 60 km from the airport. Reachable in 50 minutes with TORVIAN VIP transfer.',
  description_de = 'Tekirova ist ein kleiner, ruhiger Ferienort südlich von Kemer, umgeben von Natur. Bekannt für die Nähe zur Olympos-Seilbahn und der antiken Stadt Phaselis. Etwa 60 km vom Flughafen, in 50 Minuten mit TORVIAN VIP-Transfer.',
  description_pl = 'Tekirova to mała, spokojna miejscowość turystyczna na południe od Kemer, otoczona naturą. Znana z bliskości kolejki na górę Tahtalı i antycznego miasta Phaselis. Około 60 km od lotniska, dojazd w 50 minut transferem VIP TORVIAN.',
  description_ru = 'Текирова — небольшой тихий курортный посёлок к югу от Кемера, погружённый в природу. Известен близостью к канатной дороге Олимпос (гора Тахталы) и античному городу Фаселис. 60 км от аэропорта — доберётесь за 50 минут с VIP-трансфером TORVIAN.'
WHERE slug = 'tekirova';

-- ============================================
-- 19. CAMYUVA
-- ============================================
UPDATE regions SET
  description_tr = 'Çamyuva, Kemer''in hemen güneyinde çam ağaçlarıyla çevrili huzurlu bir sahil beldesidir. Aileler ve çiftler için ideal olan bu bölge, doğal güzellikleri ve temiz deniziyle öne çıkar. Havalimanına yaklaşık 55 km mesafededir ve TORVIAN VIP transfer ile 45 dakikada ulaşılabilir.',
  description_en = 'Çamyuva is a serene coastal village just south of Kemer, surrounded by pine trees. Ideal for families and couples, it stands out with its natural beauty and clean sea. About 55 km from the airport, reachable in 45 minutes with TORVIAN VIP transfer.',
  description_de = 'Çamyuva ist ein ruhiges Küstendorf südlich von Kemer, umgeben von Pinien. Perfekt für Familien und Paare — natürliche Schönheit und sauberes Meer. 55 km vom Flughafen, in 45 Minuten mit TORVIAN VIP-Transfer.',
  description_pl = 'Çamyuva to spokojna nadmorska wioska na południe od Kemer, otoczona sosnami. Idealna dla rodzin i par — wyróżnia się naturalnym pięknem i czystym morzem. 55 km od lotniska, dojazd w 45 minut transferem VIP TORVIAN.',
  description_ru = 'Чамьюва — тихий прибрежный посёлок к югу от Кемера, окружённый соснами. Идеален для семей и пар — природная красота и чистое море. 55 км от аэропорта — доберётесь за 45 минут с VIP-трансфером TORVIAN.'
WHERE slug = 'camyuva';

-- ============================================
-- 20. KIRIS
-- ============================================
UPDATE regions SET
  description_tr = 'Kiriş, Kemer''in hemen kuzeyinde deniz ve orman manzaralı küçük bir tatil bölgesidir. Sakin yapısı, temiz denizi ve doğa yürüyüş rotalarıyla tercih edilir. Havalimanına yaklaşık 50 km mesafededir ve TORVIAN VIP transfer ile 40 dakikada ulaşılabilir.',
  description_en = 'Kiriş is a small resort area just north of Kemer, with sea and forest views. Preferred for its peaceful nature, clean sea, and hiking trails, it sits about 50 km from the airport. Reachable in 40 minutes with TORVIAN VIP transfer.',
  description_de = 'Kiriş ist ein kleines Urlaubsgebiet nördlich von Kemer mit Meer- und Waldblick. Beliebt für seine ruhige Natur, sauberes Meer und Wanderwege. 50 km vom Flughafen, in 40 Minuten mit TORVIAN VIP-Transfer.',
  description_pl = 'Kiriş to mały region wypoczynkowy na północ od Kemer z widokiem na morze i las. Ceniony za spokojną przyrodę, czyste morze i szlaki turystyczne. 50 km od lotniska, dojazd w 40 minut transferem VIP TORVIAN.',
  description_ru = 'Кириш — небольшой курортный район к северу от Кемера с видом на море и лес. Ценится за тихую природу, чистое море и пешеходные тропы. 50 km от аэропорта — доберётесь за 40 минут с VIP-трансфером TORVIAN.'
WHERE slug = 'kiris';
